import{_ as a,C as o,o as n,c as i,E as r,a2 as s}from"./chunks/framework.CkaEw-3u.js";const h=JSON.parse('{"title":"アニメーションを時間差で展開する","description":"1つのキーフレームアニメーションを複数の文字・パーツへ時間差付きで複製する手順","frontmatter":{"title":"アニメーションを時間差で展開する","description":"1つのキーフレームアニメーションを複数の文字・パーツへ時間差付きで複製する手順","pageClass":"feature-guide","aside":false,"head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/features/feature-offset-animation.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"ja_JP"}],["meta",{"property":"og:title","content":"アニメーションを時間差で展開する | Mug Typography Manual"}],["meta",{"property":"og:description","content":"1つのキーフレームアニメーションを複数の文字・パーツへ時間差付きで複製する手順"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/features/feature-offset-animation.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"property":"og:image:type","content":"image/jpeg"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"アニメーションを時間差で展開する | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"1つのキーフレームアニメーションを複数の文字・パーツへ時間差付きで複製する手順"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"features/feature-offset-animation.md","filePath":"features/feature-offset-animation.md"}'),p={name:"features/feature-offset-animation.md"};function c(l,e,g,m,u,d){const t=o("FeatureHero");return n(),i("div",null,[r(t,{"is-new":"",eyebrow:"OFFSET ANIMATION",title:"ひとつの動きを文字全体へ展開する",description:"1文字に作成したキーフレームアニメーションを、ほかの文字やパーツへ時間差付きで複製。Frame Offsetを指定するだけで、文字が順番に動き出すFollowerのような連続アニメーションをすばやく作成できます。",image:"/image/offset-animation.webp","image-alt":"文字ごとに開始タイミングをずらした時間差アニメーション","detail-link":"/reference/reference-copy-paste#paste-animation-with-offset","point-one":"1つの動きから展開","point-two":"Frame Offsetで時間差","point-three":"展開順を自由に指定"}),e[0]||(e[0]=s('<h2 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h2><ol><li>元となる文字またはパーツ1つに、キーフレームアニメーションを作成します。</li><li><strong>Page</strong> を <code>Copy / Paste</code> にします。</li><li>手順1でアニメーションを作成した文字・パーツを選択し、<strong>Copy Selection</strong> を押します。</li><li><strong>Paste Target Attributes</strong> で、複製したいアニメーションの項目をONにします。</li><li>プレビュー画面で、貼り付け先の文字・パーツを複数選択します。</li><li><strong>Frame Offset</strong> に、対象ごとにずらすフレーム数を入力します。</li><li><strong>Paste Animation with Offset</strong> を押します。</li></ol><p>コピー元を基準（ずれなし）として、貼り付け先には <strong>Frame Offset</strong> の1倍、2倍…と累積した時間差でアニメーション全体が複製されます。<strong>Frame Offset</strong> を <code>3</code> にすると各対象が3フレームずつ遅れて動き出し、<code>-3</code> にすると時間方向が逆になります。</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>貼り付け先の文字・パーツに設定済みだったアニメーションは、チェック対象のパラメーターについてすべて消え、コピー元の内容で置き換えられます。</p></div><h2 id="fusionページでの注意" tabindex="-1">Fusionページでの注意 <a class="header-anchor" href="#fusionページでの注意" aria-label="Permalink to &quot;Fusionページでの注意&quot;">​</a></h2><p>DaVinci ResolveのFusionページはOFXプラグインによるアニメーションの直接コピーに対応していないため、Editページより処理に時間がかかったり、余分なキーフレームが設定されたりする場合があります。</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Fusionページでは、手順7のあと<strong>キーフレームの反映が落ち着くまで数秒待ち</strong>、選択やチェック状態を変えずに <strong>Repair Animation Paste</strong> を押してください。想定される時刻以外に付いたキーフレームが削除され、正しい時間差に整理されます。</p></div><h2 id="展開する順序を指定する" tabindex="-1">展開する順序を指定する <a class="header-anchor" href="#展開する順序を指定する" aria-label="Permalink to &quot;展開する順序を指定する&quot;">​</a></h2><p>デフォルトでは、論理インデックス順（<code>c1</code>、<code>c2</code>…の並び）に時間差が加算されます。<strong>Order</strong> に文字・パーツを列挙すると、その順序でオフセットを加算できます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>c3 c1 c2</span></span></code></pre></div><p>上の例では3文字目が最初（<code>Frame Offset × 1</code>）、1文字目が次（<code>Frame Offset × 2</code>）…の順に動き出します。書式はWrite OnのManual Orderと同じで、<code>p2-p5</code> のような範囲指定も使用できます。未指定の対象は論理インデックス順で末尾に続きます。</p><p>詳しい仕様（2Dパラメーターの軸の扱い、色チャンネルのキーフレーム条件など）は「<a href="/mug-typography-docs/reference/reference-copy-paste.html#paste-animation-with-offset">コピー・ペースト (Copy / Paste)</a>」を参照してください。</p>',12))])}const y=a(p,[["render",c]]);export{h as __pageData,y as default};
